+
+    const result = await sendMedia!({
+      cfg,
+      to: "+15555550124",
+      text: "caption",
+      mediaUrl: "https://example.com/file.jpg",
+      mediaLocalRoots: ["/tmp/media"],
+      accountId: "default",
+      deps: { sendSignal },
+    });
+
+    expect(sendSignal).toHaveBeenCalledWith(
+      "+15555550124",
+      "caption",
