+        mediaUrl: "https://example.com/file.jpg",
+        mediaLocalRoots: ["/tmp/media"],
+        accountId: "default",
+        maxBytes: 8 * 1024 * 1024,
+      }),
+    );
+    expect(result).toEqual({ channel: "signal", messageId: "sig-media-1", timestamp: 456 });
+  });
+});

