+        mediaUrl: "https://example.com/1.jpg",
+        quoteText: "quoted",
+        buttons: [[{ text: "Approve", callback_data: "ok" }]],
+      }),
+    );
+    expect(sendTelegram).toHaveBeenNthCalledWith(
